  ('ciso', 'new integrations added without a threat model, and security roadmaps that assume the perimeter will hold', ARRAY['threat modelling','security control design','incident response planning','third-party risk assessment','breach impact analysis']),
  ('caio', 'AI initiatives justified by hype rather than a measured use case, and model spend with no owner or evaluation baseline', ARRAY['AI use case triage','model spend governance','AI risk assessment','build vs API strategy','evaluation baseline design']),
  ('cdo', 'board metrics that cannot be traced back to the warehouse, and dashboards built on fields with no owner or lineage', ARRAY['data model governance','data quality monitoring','lineage documentation','metric definition standardisation','warehouse-to-board reconciliation']),
